qry:select.qry:xquery:
		for $r in sql('
		SELECT CYD01_CURSOS.oi_curso,
		CYD01_CURSOS.c_curso,
		CYD01_CURSOS.d_curso,
		CYD02_DICTADOS.oi_dictado,				
		CYD02_DICTADOS.d_dictado,
		CYD02_DICTADOS.f_inicio,
		CYD02_DICTADOS.f_fin				
		FROM CYD02_DICTADOS, CYD01_CURSOS
		JOIN CYD02_DICTADOS.oi_curso INNER CYD01_CURSOS.oi_curso 
		WHERE CYD01_CURSOS.oi_curso = {#PARAM:@oi_curso}
    {%? (#PARAMIN:@f_desde!='')
			{% AND CYD02_DICTADOS.f_inicio >= {Datetime(#PARAMIN:@f_desde)} %}
			{%  %} 
		%}
		{%? (#PARAMIN:@f_hasta!='')
			{% AND CYD02_DICTADOS.f_inicio <= {Datetime(#PARAMIN:@f_hasta)} %}
			{%  %}
		%}
		{%? (string(#PARAMIN:DICTADOS/DICTADO/@id)!='') 
			{% AND CYD02_DICTADOS.oi_dictado in ({%=string(#PARAMIN:DICTADOS/DICTADO/@id)%}) %} 
			{%  %} 
		%}			
')/ROWS/ROW
